using System;using System.Collections.Generic;using System.Linq;class A{static int W,H;static int[,]T,LK;static int[][]RG={new[]{0},new[]{1},new[]{2,3},new[]{3,2},new[]{4,5},new[]{5,4},new[]{6,7,8,9},new[]{7,8,9,6},new[]{8,9,6,7},new[]{9,6,7,8},new[]{10,11,12,13},new[]{11,12,13,10},new[]{12,13,10,11},new[]{13,10,11,12}};static int[]DX={0,1,0,-1},DY={-1,0,1,0},OPP={2,3,0,1};static Dictionary<int,int>rot=new();static Dictionary<int,Dictionary<int,int>>RM=new();static int Gx(int t,int e)=>RM.ContainsKey(t)&&RM[t].ContainsKey(e)?RM[t][e]:-1;static int Gt(int x,int y){int k=y*99+x;return rot.ContainsKey(k)?rot[k]:T[y,x];}static List<(int,int,int)>plan=new();static bool Dfs(int x,int y,int e){if(y>=H)return true;if(x<0||x>=W||y<0)return false;int o=T[y,x],k=y*99+x;foreach(var c in RG[o]){if(LK[y,x]==1&&c!=Gt(x,y))continue;int ex=Gx(c,e);if(ex<0)continue;int nx=x+DX[ex],ny=y+DY[ex],ne=OPP[ex];int prev=rot.ContainsKey(k)?rot[k]:-1;rot[k]=c;if(Dfs(nx,ny,ne)){if(c!=T[y,x])plan.Add((x,y,c));return true;}if(prev>=0)rot[k]=prev;else rot.Remove(k);}return false;}static void Main(){var p=Console.ReadLine().Split(' ');W=int.Parse(p[0]);H=int.Parse(p[1]);T=new int[H,W];LK=new int[H,W];int[][]rm={new int[0],new[]{0,2,1,2,3,2},new[]{1,3,3,1},new[]{0,2},new[]{0,3,1,2},new[]{0,1,1,2},new[]{1,3,3,1},new[]{0,2,1,2},new[]{3,2,1,2},new[]{0,2,3,2},new[]{0,3},new[]{0,1},new[]{1,2},new[]{3,2}};for(int i=0;i<14;i++){var m=new Dictionary<int,int>();for(int j=0;j<rm[i].Length;j+=2)m[rm[i][j]]=rm[i][j+1];RM[i]=m;}for(int y=0;y<H;y++){p=Console.ReadLine().Split(' ');for(int x=0;x<W;x++){int v=int.Parse(p[x]);LK[y,x]=v<0?1:0;T[y,x]=Math.Abs(v);}}int EX=int.Parse(Console.ReadLine());var Q=new List<string>();for(;;){p=Console.ReadLine().Split(' ');int yi=int.Parse(p[0]),xi=int.Parse(p[1]);int e=p[2][0]=='T'?0:p[2][0]=='R'?1:3;int R=int.Parse(Console.ReadLine());for(int i=0;i<R;i++)Console.ReadLine();if(Q.Count==0){rot.Clear();plan.Clear();if(Dfs(xi,yi,e))foreach(var(sx,sy,tgt)in plan){int o=T[sy,sx],r=Array.IndexOf(RG[o],tgt);if(r<=0)continue;string d=r<=2?"RIGHT":"LEFT";int cnt=r<=2?r:4-r;for(int i=0;i<cnt;i++)Q.Add($"{sx} {sy} {d}");T[sy,sx]=tgt;}}Console.WriteLine(Q.Count>0?Q[0]:"WAIT");if(Q.Count>0)Q.RemoveAt(0);}}}